import * as React from 'react';
import { graphql } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import Layout from '../../components/layout';
import Link from '../../components/common/link';
import SectionMenu from '../../components/sections/menu';
import { Seo } from '../../components/seo';
import { works } from '../../libs/works';

export default function WorksTemplate(props) {
  const { data, params } = props;
  const slug = params.frontmatter__slug;

  const { markdownRemark } = data; // data.markdownRemark holds your post data
  const { html } = markdownRemark;

  const images = data.allFile.edges
    .filter(edge => {
      const result = edge.node.name.match(
        /^portfolio_works_(\d{8}_.+)_(\d{2})$/
      );

      if (!result || !result[1] || !result[2]) return false;

      // thumbnail
      if (result[2] === '00') return false;

      const name = result[1].replace(/_/g, '-');

      return name === slug;
    })
    .map(({ node }) => getImage(node));

  const currentIndex = works.findIndex(({ link }) => link === slug);
  const nextIndex = (currentIndex + 1) % works.length;
  const prevIndex = currentIndex === 0 ? works.length - 1 : currentIndex - 1;

  const currentData = works[currentIndex];
  const nextData = works[nextIndex];
  const prevData = works[prevIndex];

  return (
    <Layout>
      <SectionMenu />
      <Box py={10}>
        <Grid container justifyContent='center' spacing={4}>
          {images.map((image, i) => {
            const isPortrait = image.width <= image.height;
            const floatWidth = isPortrait ? '50%' : '75%';

            return (
              <Grid item xs={12} key={i}>
                <Box
                  sx={{
                    width: {
                      sm: floatWidth,
                      xs: '100%'
                    },
                    mx: 'auto',
                    pointerEvents: 'none',
                    userSelect: 'none'
                  }}
                  onClick={e => e.preventDefault()}
                  onMouseDown={e => e.preventDefault()}
                  onMouseUp={e => e.preventDefault()}
                  onContextMenu={e => {
                    e.preventDefault();
                  }}
                >
                  <GatsbyImage
                    image={image}
                    alt={`image-${i}`}
                    style={{
                      pointerEvents: 'none',
                      userSelect: 'none'
                    }}
                  />
                </Box>
              </Grid>
            );
          })}
          <Grid item xs={12}>
            <div dangerouslySetInnerHTML={{ __html: html }} />
            <Typography sx={{ letterSpacing: '0.25rem', textAlign: 'center' }}>
              {currentData.title}
            </Typography>
            <Typography sx={{ mt: 2, textAlign: 'center' }}>
              {currentData.description}
            </Typography>
          </Grid>
          <Grid item xs={12}>
            <Box
              sx={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: {
                  xs: 'center'
                },
                flexDirection: {
                  md: 'row',
                  xs: 'column'
                },
                mt: 5
              }}
            >
              <Box my={1}>
                {/*
                <Link href={`/works/${prevData.link}/`}>&lt; Prev</Link>
                */}
                <Link href={`/works/${prevData.link}/`}>
                  <Typography variant='body2'>&lt; {prevData.title}</Typography>
                </Link>
              </Box>
              <Box my={1}>
                {/*
                <Link href={`/works/${nextData.link}/`}>Next &gt;</Link>
                */}
                <Link href={`/works/${nextData.link}/`}>
                  <Typography variant='body2'>{nextData.title} &gt;</Typography>
                </Link>
              </Box>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </Layout>
  );
}

export const pageQuery = graphql`
  query ($id: String!) {
    markdownRemark(id: { eq: $id }) {
      html
      frontmatter {
        slug
      }
    }
    allFile(
      sort: { relativePath: ASC }
      filter: { relativeDirectory: { eq: "works" } }
    ) {
      edges {
        node {
          relativeDirectory
          childImageSharp {
            gatsbyImageData(width: 1920)
          }
          name
        }
      }
    }
  }
`;

export const Head = ({ params }) => {
  const slug = params.frontmatter__slug;

  const currentIndex = works.findIndex(({ link }) => link === slug);

  const { title } = works[currentIndex];

  return <Seo title={title} />;
};
